#include "dumbdisplay_turtle.h"
#include <WiFi.h>
#include "dumbdisplay.h"
#include "wifidumbdisplay.h"

static DDWiFiServerIO* ddio = nullptr;
static DumbDisplay* dd = nullptr;
static TurtleDDLayer* t = nullptr;

void dd_turtle_setup(const char* ssid, const char* password, int width, int height) {
  WiFi.begin(ssid, password);
  while (WiFi.status() != WL_CONNECTED) { delay(500); }
  ddio = new DDWiFiServerIO(nullptr, nullptr, 10201);
  dd = new DumbDisplay(ddio);
  t = dd->createTurtleLayer(width, height);
  t->setTextSize(2);
  t->penColor("white");
  Serial.println("[dd_turtle] Ready");
}

void dd_turtle_fwd(int steps) { if (t) t->forward(steps); }
void dd_turtle_bk(int steps) { if (t) t->backward(steps); }
void dd_turtle_rt(int degrees) { if (t) t->rightTurn(degrees); }
void dd_turtle_lt(int degrees) { if (t) t->leftTurn(degrees); }
void dd_turtle_pu() { if (t) t->penUp(); }
void dd_turtle_pd() { if (t) t->penDown(); }
void dd_turtle_color(const char* color) { if (t) t->penColor(color); }
void dd_turtle_width(int w) { if (t) t->penSize(w); }
void dd_turtle_home() { if (t) t->home(); }
void dd_turtle_clear() { if (t) t->clear(); }
